declare @c varchar(1024)
if (cast(@tt_sx1 as tinyint) + cast(@tt_sx2 as tinyint) + cast(@tt_sx3 as tinyint) <> 0) begin
  set @c = @tt_sx1 + ',' + @tt_sx2 + ',' + @tt_sx3
  set @c = N'' + replace(replace(replace(@c, '1', 'nh_dc1'), '2', 'nh_dc2'), '3', 'nh_dc3') + ''
  set @c = N'' + replace(replace(replace(@c, '0,', ''), ',0', ''), '0', '') + ''
end

select cast(@ngay1 as smalldatetime) as tu_ngay, cast(@ngay2 as smalldatetime) as den_ngay
exec rs_rptTS2list @ngay1, @ngay2, @ma_loai, @ma_bp, @nhom_1, @nhom_2, @nhom_3, @c, @ma_dvcs, N'ma_dc', @@language, @@userID, @@admin






        /* <flatten type="Javascript"> */
var x = parseInt(this.getItemValue('tt_sx1')), y = parseInt(this.getItemValue('tt_sx2')), z = parseInt(this.getItemValue('tt_sx3'));
if ((x == y && x != 0) || (x == z && x != 0) || (y == z && y != 0)){
  this._checked = false;
  $func.hideWait(this.get_id());
  $message.show(String.format($df.getResources(this._language, 'Message.RequiredField'), this.getItem('tt_sx1').field.Label), String.format('$find(\'{0}\').getItem(\'{1}\').focus()', this.get_id(), 'tt_sx1'));
}
/* </flatten> */






